targets.expr:
sum by (application, instance) (
  rate(
    http_server_requests_seconds_count{
      application=~"$application"
    }[30s]
  )
)

sum by (application) (
  rate(
    http_server_requests_seconds_sum{
      application=~"$application",
      status!~"5.."
    }[5m]
  )
)
/
sum by (application) (
  rate(
    http_server_requests_seconds_count{
      application=~"$application",
      status!~"5.."
    }[5m]
  )
)
